-- Alinha a tabela public.stickers com o seed oficial de 360 figurinhas.
-- Seguro para rodar em bancos existentes: atualiza metadados sem mexer no inventário das usuárias.

alter table public.stickers
  add column if not exists category text;

on conflict (number) do update set
  slug = excluded.slug,
  name = excluded.name,
  author = excluded.author,
  type = excluded.type,
  cover_url = excluded.cover_url,
  amazon_url = excluded.amazon_url,
  category = excluded.category;

do $$
begin
  if (select count(*) from public.stickers where number between 1 and 360) <> 360 then
    raise exception 'A tabela public.stickers nao ficou com as 360 figurinhas esperadas.';
  end if;
end $$;
